{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "tools": [
      {
        "name": "get_balance",
        "description": "Retrieves the current balance for a specific account.",
        "inputSchema": {
          "type": "object",
          "properties": {
            "account_id": {
              "type": "string",
              "description": "The unique identifier for the bank account (e.g., 'ACC-12345')."
            }
          },
          "required": ["account_id"]
        }
      },
      {
        "name": "transfer_funds",
        "description": "Moves money between two internal accounts.",
        "inputSchema": {
          "type": "object",
          "properties": {
            "source_account": {
              "type": "string",
              "description": "The account ID to withdraw from."
            },
            "destination_account": {
              "type": "string",
              "description": "The account ID to deposit into."
            },
            "amount": {
              "type": "number",
              "description": "The amount of currency to transfer."
            },
            "currency": {
              "type": "string",
              "description": "The ISO 4217 currency code.",
              "default": "USD"
            }
          },
          "required": ["source_account", "destination_account", "amount"]
        }
      }
    ]
  }
}

{
  "jsonrpc": "2.0",
  "id": 2,
  "result": {
    "content": [
      {
        "type": "text",
        "text": "The current balance for account 12345 is $1,250.42."
      }
    ],
    "isError": false
  }
}

